/**
 * Formula Sheet Button Component
 *
 * Fetches formula sheet data and renders a toggle button.
 * Hidden if no formula sheet is available for the lesson.
 */

import { FileText, Loader2 } from 'lucide-react'
import useSWR from 'swr'
import { useTranslations } from 'next-intl-react'
import { useState } from 'react'
import { cn } from '@/infra/utils/ui'

interface FormulaSheetData {
  id: string
  name: string
  locale: string
  kind: 'richtext' | 'pdf'
  content?: unknown
  pdfFile?: {
    id: string
    url?: string | null
    filename?: string | null
  } | null
  pdfStatus?: 'ok' | 'missing'
  isEmpty?: boolean
}

interface FormulaSheetButtonProps {
  lessonId: string
  disabled?: boolean
  onOpen?: (data: FormulaSheetData) => void
}

const fetcher = async (url: string) => {
  const res = await fetch(url)
  if (!res.ok) {
    const error = new Error('Failed to fetch formula sheet')
    throw error
  }
  return res.json()
}

export function FormulaSheetButton({ lessonId, disabled, onOpen }: FormulaSheetButtonProps) {
  const t = useTranslations('courses')
  const [isOpen, setIsOpen] = useState(false)

  // Don't render if no lessonId
  if (!lessonId) {
    return null
  }

  const { data, error, isLoading } = useSWR<{ formulaSheet: FormulaSheetData | null }>(
    `/api/formula-sheet?lessonId=${lessonId}`,
    fetcher,
    {
      revalidateOnFocus: false,
      dedupingInterval: 60000, // 1 minute
    }
  )

  // Don't render if loading or error or no sheet
  if (isLoading || error || !data?.formulaSheet) {
    return null
  }

  const sheet = data.formulaSheet

  // Hide button if sheet is empty or has missing PDF
  if (sheet.isEmpty || sheet.pdfStatus === 'missing') {
    return null
  }

  const handleClick = () => {
    const newIsOpen = !isOpen
    setIsOpen(newIsOpen)
    if (newIsOpen && onOpen) {
      onOpen(sheet)
    }
  }

  return (
    <button
      type="button"
      onClick={handleClick}
      disabled={disabled}
      className={cn(
        'flex items-center gap-2 px-3 py-2 rounded-lg text-sm font-medium transition-colors',
        'bg-primary/10 text-primary border border-primary/20 hover:bg-primary/20',
        disabled && 'opacity-50 cursor-not-allowed'
      )}
      aria-label={t('formulaSheet')}
    >
      <FileText className="w-4 h-4" />
      <span>{t('formulaSheet')}</span>
    </button>
  )
}

export type { FormulaSheetData }

