                      type: 'text',
                      version: 1,
                    },
                  ],
                  type: 'heading',
                  tag: 'h2',
                  version: 1,
                  direction: 'ltr',
                  format: '',
                },
              ],
              type: 'paragraph',
              version: 1,
              direction: 'ltr',
              format: '',
            },
            {
              children: [
                {
                  text: 'משוואה ריבועית: ',
                  type: 'text',
                  version: 1,
                },
                {
                  text: 'x = (-b ± √(b²-4ac)) / 2a',
                  type: 'text',
                  version: 1,
                  format: 'italic',
                },
              ],
              type: 'paragraph',
              version: 1,
              direction: 'ltr',
              format: '',
            },
            {
              children: [
                {
                  text: 'נוסחאות טריגונומטריה',
                  type: 'text',
                  version: 1,
                },
              ],
              type: 'heading',
              tag: 'h2',
              version: 1,
              direction: 'ltr',
              format: '',
            },
            {
              children: [
                {
                  text: 'sin²α + cos²α = 1',
                  type: 'text',
                  version: 1,
                  format: 'italic',
                },
              ],
              type: 'paragraph',
              version: 1,
              direction: 'ltr',
              format: '',
            },
            {
              children: [
                {
                  text: 'נגזרות',
                  type: 'text',
                  version: 1,
                },
              ],
              type: 'heading',
              tag: 'h2',
              version: 1,
              direction: 'ltr',
              format: '',
            },
            {
              children: [
                {
                  text: "(f + g)' = f' + g'",
                  type: 'text',
                  version: 1,
                  format: 'italic',
                },
              ],
              type: 'paragraph',
              version: 1,
              direction: 'ltr',
              format: '',
            },
          ],
          type: 'root',
          version: 1,
        },
      }

      // Get default tenant
      const tenants = await payload.find({
        collection: 'tenants',
        limit: 1,
        depth: 0,
        overrideAccess: true,
      })

      const tenantId = tenants.docs[0]?.id

      if (!tenantId) {
        return { created: false, linked: false, error: 'No default tenant found' }
      }

      const newSheet = await payload.create({
        collection: 'formula-sheets',
        data: {
          name: '471 - נוסחאות - v1',
          locale: 'he',
          tenant: tenantId,
          content: formulaSheetContent,
        },
        overrideAccess: true,
      })

      sheetId = newSheet.id
      payload.logger?.info('[seedFormulaSheet471] Created formula sheet with id:', sheetId)
    }

    // Step 3: Find course 471 and link the formula sheet
    // Course 471 could be identified by courseLabel containing "471" or title containing "471"
    const courses = await payload.find({
      collection: 'courses',
      where: {
        or: [
          { courseLabel: { equals: '471' } },
          { courseLabel: { contains: '471' } },
          { title: { contains: '471' } },
        ],
      },
      limit: 1,
      depth: 0,
      overrideAccess: true,
    })

    if (courses.docs.length === 0) {
      payload.logger?.warn('[seedFormulaSheet471] Course 471 not found, skipping linking')
      return { created: true, linked: false, error: 'Course 471 not found' }
    }

    const course = courses.docs[0]

    // Check if already linked
    if (course.defaultFormulaSheet) {
      const existingLinkId =
        typeof course.defaultFormulaSheet === 'string'
          ? course.defaultFormulaSheet
          : course.defaultFormulaSheet?.id

      if (existingLinkId === sheetId) {
        payload.logger?.info('[seedFormulaSheet471] Formula sheet already linked to course')
        return { created: false, linked: true }
      }
    }

    // Link the formula sheet to the course
    await payload.update({
      collection: 'courses',
      id: course.id,
      data: {
        defaultFormulaSheet: sheetId,
      },
      overrideAccess: true,
    })

    payload.logger?.info('[seedFormulaSheet471] Linked formula sheet to course:', course.id)

    return { created: existingSheet.docs.length === 0, linked: true }
  } catch (error) {
    payload.logger?.error('[seedFormulaSheet471] Error:', error)
    return { created: false, linked: false, error: String(error) }
  }
}

